# Submits 25 test personas to the questionnaire endpoint.
# Reads persona data from seed-test-plans.js (the JS array is valid JSON-ish).
# Usage: powershell -File scripts/seed-test-plans.ps1

$SiteUrl = if ($env:SITE_URL) { $env:SITE_URL } else { "https://alongsideai.ai" }
$Endpoint = "$SiteUrl/.netlify/functions/submit-questionnaire"
$DelaySeconds = 5

# Build persona payloads inline (PowerShell hashtables).
$personas = @(
  @{ name="Frank"; situation="business"; comfort="basics"; work="I own three commercial rental properties in Pasadena. I handle everything - leases, maintenance requests, rent collection, bookkeeping. I've got a part-time property manager but she mostly handles showings and tenant calls."; creates="Leases, maintenance work orders, rent invoices, monthly owner statements, bank reconciliations"; team="partner"; typical_week="Mondays I review the financials and pay bills. Tuesday through Thursday I'm usually visiting properties or meeting with contractors. Fridays I try to catch up on paperwork but it always spills into Saturday."; location_today="mix"; location_wanted="Anywhere - I want to be able to handle urgent stuff from my phone when I'm on a job site or traveling."; devices="iphone, mac, ipad"; subscriptions="accounting, storage"; subscriptions_other="AppFolio for property management"; data_lives="QuickBooks Desktop on my office iMac, leases in a filing cabinet, tenant contact info split between my phone and AppFolio. Some stuff is in Google Drive but it's a mess."; tool_hated="QuickBooks Desktop"; tool_hated_why="I can't access it unless I'm sitting at my desk. Entering a bill takes fifteen clicks. The interface looks like it was designed in 2003 because it was."; friction="Keeping track of lease expirations, matching deposits to invoices, chasing late rent, paper everywhere. I spend half of Friday just looking for documents."; manual_tasks="1) Matching deposits to invoices in QuickBooks. 2) Sending the same intake email to every new tenant. 3) Manually updating a spreadsheet of lease dates."; already_tried="Tried to move to QuickBooks Online two years ago but my accountant said it couldn't handle the property reports I need. AppFolio helps but the accounting side is limited."; given_up_on="Having a clean, organized file system. I've tried Google Drive, Dropbox, even those paper organizer systems. Nothing sticks longer than a month."; inbox="overwhelmed"; inbox_note="I can never find that one email from the contractor two weeks ago. I get 80+ emails a day and maybe 10 matter."; wish="I wish I could work from anywhere and not be tied to my office computer. And I wish rent collection was completely hands-off."; explain_once="How I price a lease. Which contractors I trust for different jobs. Which tenants are good about paying on time and which ones need a reminder call on the 3rd. The rules about security deposits in California."; success_6mo="I'm spending winters somewhere warm. My property manager handles the inbox. Rent collects itself. I check a dashboard once a week instead of opening QuickBooks every day."; priority="time"; tried_ai="little"; nervous="I'm worried about putting tenant information - social security numbers, bank details - into these things. My attorney would have my head."; cloud_comfort="familiar"; urgency="asap"; budget_posture="100_250" },

  @{ name="Diane"; situation="business"; comfort="okay"; work="I run a boutique dental practice with four hygienists and two front desk staff. We see about 25 patients a day. I'm the only dentist."; creates="Treatment plans, patient communications, insurance claims, employee schedules, marketing emails to patients"; team="small"; typical_week="Patient care Mon-Thu 8am-5pm. Fridays are admin - payroll, ordering supplies, reviewing the books. One evening a week I try to write the monthly patient newsletter but I never finish it."; location_today="office"; location_wanted="I'd love to review the schedule and handle admin stuff from home in the morning before I drive in."; devices="iphone, pc"; subscriptions="m365, accounting, scheduling, email_marketing"; subscriptions_other="Dentrix for practice management, Weave for patient communications"; data_lives="Dentrix has all patient records. QuickBooks Online for bookkeeping. Staff schedule is an Excel file my office manager updates. Marketing stuff is in Constant Contact. Payroll is through ADP."; tool_hated="Constant Contact"; tool_hated_why="The email editor is clunky, templates look dated, and I can never figure out how to segment my list properly."; friction="Writing patient follow-up emails after consultations. Every one is slightly different but 80% the same. Also: insurance pre-authorization is pure paperwork torture."; manual_tasks="1) Writing individual follow-up emails after big treatment consultations. 2) Calling patients who haven't been in for 6+ months. 3) Manually entering supply orders into QuickBooks."; already_tried="My daughter set me up with a ChatGPT account. I used it a few times to draft emails but I kept forgetting to open it."; inbox="manageable"; wish="I wish I had a way to draft personalized patient emails that sound like me, not a robot, in about 30 seconds instead of 15 minutes."; explain_once="Our recall process. When to use which template. How I talk to nervous patients versus routine ones."; success_6mo="The newsletter goes out every month without me agonizing over it. Follow-up emails write themselves. I spend Friday afternoons doing something other than admin."; priority="time"; tried_ai="little"; nervous="HIPAA. That's the whole answer. Patient data cannot leave our systems."; cloud_comfort="nervous"; cloud_comfort_note="We're a healthcare practice. Everything has to be HIPAA-compliant."; urgency="month"; budget_posture="50_100" },

  @{ name="Carlos"; situation="business"; comfort="comfortable"; work="I own a landscaping company. 12 employees, mostly field crews. We do residential and commercial maintenance plus design-build projects."; creates="Estimates, invoices, contracts, job schedules, crew assignments, supply orders"; team="small"; typical_week="Monday morning I assign crews and review the week's jobs. Tues-Thurs I bounce between job sites and meeting with new clients for estimates. Friday is billing and payroll."; location_today="anywhere"; location_wanted="Same - but I want it to actually work instead of me juggling three apps on my phone in a truck."; devices="android, pc"; subscriptions="accounting, invoicing"; subscriptions_other="Jobber for scheduling and dispatch"; data_lives="Jobber has client info and job history. QuickBooks Online for finances. A lot of notes are just in text messages to my crews. Photos of completed work live in my phone gallery."; friction="Estimating takes forever. I'm driving to a site, measuring, then going home to type it all into Jobber. Half the time I forget a measurement and have to go back."; manual_tasks="1) Typing up estimates from handwritten notes. 2) Texting crew leads individual schedules every Monday morning. 3) Sorting job photos into client folders."; already_tried="We switched to Jobber last year and it helped a lot with scheduling. But the estimating is still slow."; inbox="manageable"; wish="I want to take a photo of a yard and get a rough estimate template back."; success_6mo="Estimates go out same day instead of three days later. My crews get their schedules automatically. I have an organized photo library of our work for proposals."; priority="money"; tried_ai="no"; nervous="Not really nervous - just haven't had time to look into it."; cloud_comfort="fine"; urgency="asap"; budget_posture="50_100" },

  @{ name="Patricia"; situation="business"; comfort="basics"; work="I run a small insurance agency. Independent - I represent about eight carriers. It's me and one admin assistant."; creates="Quotes, policy summaries, renewal letters, commission tracking spreadsheets, client birthday cards"; team="partner"; typical_week="Every day is client calls and quoting. Mondays are heavy on renewals. Wednesday afternoons I try to do marketing but I'm always behind."; location_today="office"; location_wanted="Home, mostly. My husband retired last year and I'd love to be more flexible."; devices="iphone, pc"; subscriptions="m365"; subscriptions_other="Hawksoft agency management system"; data_lives="Hawksoft has everything - client info, policy details, notes. But I also have a personal Excel spreadsheet with my commission tracking because Hawksoft's reports are terrible."; tool_hated="Hawksoft"; tool_hated_why="The interface is from the 90s. You can't access it from a browser. Reporting is so bad I maintain my own Excel sheets alongside it."; friction="Quoting. Each carrier has a different portal and I'm logging into five or six of them per quote, re-entering the same information each time. A single auto quote takes me 45 minutes."; manual_tasks="1) Re-entering client data into each carrier portal when quoting. 2) Updating my commission spreadsheet monthly. 3) Sending renewal reminder letters."; already_tried="Looked at EZLynx but the migration cost was $15,000."; given_up_on="Having a proper CRM. I use Hawksoft's contact list but it's not a real CRM."; inbox="overwhelmed"; inbox_note="Carriers email constantly. I miss important renewal notices in the flood."; wish="I wish quoting didn't require logging into six different websites."; explain_once="Which carriers are competitive for which types of policies. My preferred carriers by line of business. How I calculate commissions for each carrier."; success_6mo="Quoting takes 15 minutes instead of 45. I'm not maintaining a parallel spreadsheet. I can work from home two days a week."; priority="peace"; tried_ai="no"; nervous="Client financial information. Insurance applications have social security numbers, addresses, driver's license numbers."; cloud_comfort="nervous"; cloud_comfort_note="I have E&O insurance that requires certain data handling practices."; urgency="month"; budget_posture="100_250" },

  @{ name="Jim"; situation="business"; comfort="avoid"; work="General contractor. Residential remodels mostly - kitchens, bathrooms, additions. Been doing this 35 years."; creates="Estimates, change orders, subcontractor agreements, material lists, progress photos for clients"; team="solo"; typical_week="On job sites all day, every day. Evenings and weekends I do the paperwork. My wife helps with bookkeeping but she's tired of it."; location_today="anywhere"; location_wanted="Same. But I need the paperwork to be simpler."; devices="iphone, pc"; subscriptions="accounting"; data_lives="QuickBooks on the home computer. Estimates are in Word documents. Subcontractor contacts are in my phone. A lot of job details are just in my head."; friction="Writing estimates. I know what a kitchen remodel costs in my sleep but writing it all out formal-like takes me three hours."; manual_tasks="1) Writing up estimates from scratch each time. 2) Creating material lists for the lumber yard. 3) Taking photos on my phone and texting them one by one to clients."; already_tried="My son showed me some contractor estimating software. Too complicated."; inbox="surrendered"; wish="I just want someone or something to turn my rough notes into a professional-looking estimate."; success_6mo="Estimates go out the same day I visit a site instead of a week later. My wife stops doing bookkeeping on Sundays."; priority="time"; tried_ai="no"; nervous="I don't understand it and I don't trust what I don't understand."; cloud_comfort="local"; urgency="exploring"; budget_posture="under_50" },

  @{ name="Anita"; situation="business"; comfort="okay"; work="I own a bakery and cafe. We do walk-in retail, wholesale to two grocery chains, and catering for events. 8 employees."; creates="Inventory orders, catering proposals, social media posts, employee schedules"; team="small"; typical_week="I'm in the kitchen 4am-noon baking. Afternoons are orders, admin, and trying to keep up with Instagram. Saturday mornings are our busiest retail time."; location_today="office"; location_wanted="I'd like to handle admin from home in the afternoons."; devices="iphone, ipad, mac"; subscriptions="google, accounting, scheduling"; subscriptions_other="Square for POS, Later for social media scheduling"; data_lives="Square has all our sales data. QuickBooks Online for bookkeeping. Recipes are in binders. Wholesale client info is in a Google Sheet."; friction="Social media. I know it's important but creating posts, taking good photos, writing captions eats two hours a day."; manual_tasks="1) Writing Instagram captions and scheduling posts. 2) Creating weekly employee schedules. 3) Calculating ingredient quantities when scaling recipes for catering."; already_tried="Hired a social media manager for three months. She was great but $2,000/month wasn't sustainable."; inbox="manageable"; wish="I wish social media content could mostly create itself. I'll take the photos."; success_6mo="We're posting consistently without it consuming my afternoons. Catering proposals go out fast. I actually take Sundays off."; priority="mix"; tried_ai="little"; nervous="Not really. I tried ChatGPT for writing a catering menu description once and it was decent."; cloud_comfort="fine"; urgency="asap"; budget_posture="50_100" },

  @{ name="Robert"; situation="business"; comfort="basics"; work="Small consulting firm - management consulting for mid-size manufacturing companies. Three consultants plus me."; creates="Proposals, engagement letters, project status reports, slide decks, final deliverable reports (30-50 pages)"; team="small"; typical_week="Monday is internal. Tuesday through Thursday I'm at client sites or on calls. Friday is proposal writing and business development."; location_today="mix"; location_wanted="Flexible - I travel to clients in three states."; devices="iphone, pc, ipad"; subscriptions="m365, storage, crm"; subscriptions_other="HubSpot CRM free tier, Toggl for time tracking"; data_lives="OneDrive has project files. HubSpot has client contacts and pipeline. Time entries in Toggl. Proposals are Word docs. No consistent naming convention."; friction="Proposal writing. Every proposal is 60% the same but I rewrite from scratch because I can never find the right previous one to copy from."; manual_tasks="1) Writing proposals from scratch. 2) Compiling weekly status reports from each consultant's notes. 3) Logging time."; already_tried="Tried standardizing templates in SharePoint. It lasted about six weeks."; inbox="manageable"; inbox_note="Email is my main tool. I live in Outlook. But searching for old client emails is terrible."; wish="I want a proposal engine. Feed it the client, scope, and timeline - and get a first draft back that's 80% there."; success_6mo="Proposals go out in a day instead of a week. Status reports are consistent."; priority="money"; tried_ai="regular"; nervous="Client confidentiality. We work with companies that require NDAs."; cloud_comfort="fine"; cloud_comfort_note="Already cloud-native. Just need data privacy guarantees for client-sensitive material."; urgency="asap"; budget_posture="100_250" },

  @{ name="Linda"; situation="business"; comfort="basics"; work="I own a small retail gift shop in a tourist town. Just me and two part-time employees."; creates="Purchase orders, social media posts, a monthly email newsletter, basic bookkeeping entries"; team="partner"; typical_week="I'm in the shop most days. Mornings before we open I do ordering and bookkeeping. Afternoons are floor time."; location_today="office"; location_wanted="The shop - but I want to stop taking paperwork home at night."; devices="iphone, ipad"; subscriptions="accounting, email_marketing"; subscriptions_other="Shopify for online store, Square for in-store POS"; data_lives="Shopify has online orders. Square has in-store sales. QuickBooks has the bookkeeping. Vendor contacts are in my phone and a paper Rolodex."; friction="Keeping inventory synced between the physical shop and Shopify. I sell something in store and forget to update online, then sell it twice."; manual_tasks="1) Updating Shopify inventory after in-store sales. 2) Writing product descriptions for new items. 3) Reposting product photos from Instagram to Facebook."; already_tried="Shopify has a Square integration but it never worked right."; inbox="manageable"; wish="I wish product descriptions wrote themselves. I take a photo, it figures out what it is, and gives me a nice description."; success_6mo="Inventory is synced. Every product has a description. Social media posts go out regularly."; priority="peace"; tried_ai="no"; nervous="Not nervous exactly - more overwhelmed. I don't know where to start."; cloud_comfort="familiar"; urgency="month"; budget_posture="under_50" },

  @{ name="Margaret"; situation="semi_retired"; comfort="basics"; work="I was a corporate attorney for 30 years. Now I do occasional consulting - reviewing contracts, advising on governance. Maybe 10-15 hours a week."; creates="Contract redlines, advisory memos, emails to former colleagues"; team="solo"; typical_week="No fixed schedule. Some weeks I have three calls and a document to review. Other weeks nothing."; location_today="home"; location_wanted="Home and my daughter's house in Portland - I visit for weeks at a time."; devices="iphone, mac"; subscriptions="m365"; data_lives="Everything is in Word docs and email. Some files on my Mac desktop, some in OneDrive, some I can't find at all."; friction="Document management. I have hundreds of contract templates and I can never find the right one."; manual_tasks="1) Searching through folders for a relevant prior contract. 2) Reformatting documents when clients send me PDFs. 3) Tracking my hours."; already_tried="My former firm had a document management system. I looked at getting one but they all assume you have an IT department."; inbox="manageable"; wish="I wish I could say 'find me the last contract I reviewed for a software licensing deal' and have it just appear."; success_6mo="I can find any document in under 30 seconds. My advisory work is organized."; priority="peace"; tried_ai="little"; nervous="Attorney-client privilege. If client documents end up in some AI company's training data, I have a real liability problem."; cloud_comfort="nervous"; cloud_comfort_note="Attorney-client privilege is non-negotiable."; urgency="month"; budget_posture="50_100" },

  @{ name="Howard"; situation="semi_retired"; comfort="avoid"; work="Retired cardiologist. I still do peer review for two medical journals and volunteer at a free clinic one day a week."; creates="Peer review reports, some patient notes at the clinic, travel itineraries"; team="solo"; typical_week="Two or three journal articles to review per month. Clinic is every Thursday. Rest of the time reading, gardening, or planning trips."; location_today="home"; location_wanted="Wherever we're traveling. I review articles on planes all the time."; devices="iphone, ipad, mac"; subscriptions="storage"; data_lives="Email, mostly. Some files on my Mac. Journal articles pile up in my email inbox as PDF attachments."; friction="Managing the journal review process. I get PDFs by email, make notes on paper, type up the review, email it back."; manual_tasks="1) Printing PDFs to annotate by hand. 2) Typing up handwritten review notes. 3) Organizing travel documents."; inbox="overwhelmed"; wish="I want to annotate PDFs naturally and have it turn into a proper typed review."; success_6mo="Reviews are done digitally end-to-end, no printing. Travel documents are organized."; priority="time"; tried_ai="no"; nervous="I'm 72. I'm more worried about the learning curve than privacy."; cloud_comfort="familiar"; urgency="exploring"; budget_posture="under_50" },

