  @{ name="George"; situation="semi_retired"; comfort="basics"; work="Retired school principal. Now I run a small educational consulting practice - helping schools with curriculum design and accreditation prep."; creates="Curriculum review reports, accreditation self-study documents, professional development presentations, grant narratives"; team="solo"; typical_week="Very flexible. Usually two or three client calls per week, plus writing time. I procrastinate on the writing."; location_today="home"; location_wanted="Home is great. Maybe a coffee shop sometimes."; devices="pc, iphone"; subscriptions="m365"; data_lives="OneDrive, mostly. But I have files going back 20 years on an external hard drive."; friction="Writing. I write well but slowly. A 40-page accreditation self-study takes me three weeks."; manual_tasks="1) Formatting documents to different accreditation body standards. 2) Searching through old reports for relevant language. 3) Creating slide decks for workshops."; inbox="manageable"; wish="I want a writing partner that knows education. Something that can take my outline and turn it into a solid first draft in my voice."; success_6mo="Reports take one week instead of three. I'm taking on one more client because I have the bandwidth."; priority="money"; tried_ai="little"; nervous="Accuracy. In education, if an AI makes something up it could damage my reputation."; cloud_comfort="fine"; urgency="month"; budget_posture="50_100" },

