Write-Host "Seeding 25 test plans via $Endpoint"
Write-Host "All submissions use _test: true (customer emails suppressed)`n"

for ($i = 0; $i -lt $personas.Count; $i++) {
    $p = $personas[$i]
    $label = "[{0,2}/25]" -f ($i + 1)

    # Build the payload - add test flag and contact email
    $payload = @{}
    foreach ($key in $p.Keys) {
        $payload[$key] = $p[$key]
    }
    $payload["contact"] = "test+$($p.name.ToLower())@alongsideai.ai"
    $payload["_test"] = $true

    $json = $payload | ConvertTo-Json -Depth 3 -Compress

    Write-Host "$label Submitting $($p.name) ($($p.situation))..."

    try {
        $response = Invoke-WebRequest -Uri $Endpoint -Method POST -ContentType "application/json" -Body ([System.Text.Encoding]::UTF8.GetBytes($json)) -UseBasicParsing
        Write-Host "$label   -> $($response.StatusCode) $($response.Content.Substring(0, [Math]::Min(120, $response.Content.Length)))"
    } catch {
        Write-Host "$label   -> FAILED: $($_.Exception.Message)"
    }

    if ($i -lt $personas.Count - 1) {
        Start-Sleep -Seconds 5
    }
}

Write-Host "`nDone. 25 submissions queued for plan generation."
Write-Host "Plans will generate in the background over the next 15-75 minutes."
Write-Host "Check Netlify function logs to monitor progress."
